  1→/**
  2→ * Prepare plugin package for official Claude Code marketplace submission
  3→ *
  4→ * Usage: npx tsx scripts/prepare-marketplace.ts [--validate-only]
  5→ *
  6→ * Builds the external_plugins/sequant/ directory structure required by
  7→ * https://github.com/anthropics/claude-plugins-official
  8→ */
  9→
 10→import {
 11→  existsSync,
 12→  mkdirSync,
 13→  readFileSync,
 14→  writeFileSync,
 15→  rmSync,
 16→  cpSync,
 17→  readdirSync,
 18→  statSync,
 19→} from "fs";
 20→import { join, dirname } from "path";
 21→import { fileURLToPath } from "url";
 22→
 23→const __filename = fileURLToPath(import.meta.url);
 24→const __dirname = dirname(__filename);
 25→const PROJECT_ROOT = join(__dirname, "..");
 26→const OUTPUT_DIR = join(
 27→  PROJECT_ROOT,
 28→  "dist",
 29→  "marketplace",
 30→  "external_plugins",
 31→  "sequant",
 32→);
 33→const validateOnly = process.argv.includes("--validate-only");
 34→
 35→function countSkills(dir: string): number {
 36→  let count = 0;
 37→  if (!existsSync(dir)) return 0;
 38→  for (const entry of readdirSync(dir)) {
 39→    const skillDir = join(dir, entry);
 40→    if (
 41→      statSync(skillDir).isDirectory() &&
 42→      existsSync(join(skillDir, "SKILL.md"))
 43→    ) {
 44→      count++;
 45→    }
 46→  }
 47→  return count;
 48→}
 49→
 50→function main(): void {
 51→  console.log("📦 Preparing marketplace package...\n");
 52→
 53→  // Verify prerequisites
 54→  const packageJsonPath = join(PROJECT_ROOT, "package.json");
 55→  if (!existsSync(packageJsonPath)) {
 56→    console.error("❌ package.json not found. Run from project root.");
 57→    process.exit(1);
 58→  }
 59→
 60→  const pluginJsonPath = join(PROJECT_ROOT, ".claude-plugin", "plugin.json");
 61→  if (!existsSync(pluginJsonPath)) {
 62→    console.error("❌ .claude-plugin/plugin.json not found.");
 63→    process.exit(1);
 64→  }
 65→
 66→  // Get versions
 67→  const packageJson = JSON.parse(readFileSync(packageJsonPath, "utf8"));
 68→  const pluginJson = JSON.parse(readFileSync(pluginJsonPath, "utf8"));
 69→  const version = packageJson.version;
 70→  const pluginVersion = pluginJson.version;
 71→
 72→  console.log(`Version: ${version}`);
 73→
 74→  if (version !== pluginVersion) {
 75→    console.error(
 76→      `❌ Version mismatch: package.json (${version}) != plugin.json (${pluginVersion})`,
 77→    );
 78→    console.error("   Run ./scripts/release.sh to sync versions.");
 79→    process.exit(1);
 80→  }
 81→
 82→  if (validateOnly) {
 83→    console.log("\n🔍 Validating existing marketplace package...");
 84→    if (!existsSync(OUTPUT_DIR)) {
 85→      console.error(`❌ No marketplace package found at ${OUTPUT_DIR}`);
 86→      console.error(
 87→        "   Run without --validate-only first to build the package.",
 88→      );
 89→      process.exit(1);
 90→    }
 91→  } else {
 92→    // Clean previous build
 93→    const marketplaceDir = join(PROJECT_ROOT, "dist", "marketplace");
 94→    if (existsSync(marketplaceDir)) {
 95→      rmSync(marketplaceDir, { recursive: true });
 96→    }
 97→    mkdirSync(OUTPUT_DIR, { recursive: true });
 98→
 99→    // 1. Copy plugin.json (marketplace.json is for self-hosted)
100→    console.log("📋 Copying plugin metadata...");
101→    const outputPluginDir = join(OUTPUT_DIR, ".claude-plugin");
102→    mkdirSync(outputPluginDir, { recursive: true });
103→    cpSync(pluginJsonPath, join(outputPluginDir, "plugin.json"));
104→
105→    // 2. Copy skills from templates/
106→    console.log("📋 Copying skills...");
107→    const templatesSkillsDir = join(PROJECT_ROOT, "templates", "skills");
108→    if (existsSync(templatesSkillsDir)) {
109→      cpSync(templatesSkillsDir, join(OUTPUT_DIR, "skills"), {
110→        recursive: true,
111→      });
112→    }
113→
114→    // 3. Copy hooks
115→    console.log("📋 Copying hooks...");
116→    const templatesHooksDir = join(PROJECT_ROOT, "templates", "hooks");
117→    if (existsSync(templatesHooksDir)) {
118→      const outputHooksDir = join(OUTPUT_DIR, "hooks");
119→      mkdirSync(outputHooksDir, { recursive: true });
120→      cpSync(templatesHooksDir, outputHooksDir, { recursive: true });
121→    }
122→
123→    // 4. Generate README
124→    console.log("📋 Generating README...");
125→    writeFileSync(join(OUTPUT_DIR, "README.md"), README_CONTENT);
126→  }
127→
128→  // Validate
129→  validate();
130→}
131→
132→function validate(): void {
133→  console.log("\n🔍 Validating marketplace structure...");
134→  let errors = 0;
135→
136→  const outputPluginJson = join(OUTPUT_DIR, ".claude-plugin", "plugin.json");
137→  if (existsSync(outputPluginJson)) {
138→    console.log("  ✅ .claude-plugin/plugin.json");
139→
140→    const plugin = JSON.parse(readFileSync(outputPluginJson, "utf8"));
141→
142→    // Required fields
143→    for (const field of ["name", "description", "version", "author"]) {
144→      if (!plugin[field]) {
145→        console.error(`  ❌ plugin.json missing required field: ${field}`);
146→        errors++;
147→      }
148→    }
149→
150→    // Recommended fields
151→    for (const field of ["homepage", "repository", "license", "keywords"]) {
152→      if (!plugin[field]) {
153→        console.warn(`  ⚠️  plugin.json missing recommended field: ${field}`);
154→      }
155→    }
156→  } else {
157→    console.error("  ❌ .claude-plugin/plugin.json (MISSING)");
158→    errors++;
159→  }
160→
161→  const skillsDir = join(OUTPUT_DIR, "skills");
162→  if (existsSync(skillsDir)) {
163→    const count = countSkills(skillsDir);
164→    console.log(`  ✅ skills/ (${count} skills found)`);
165→  } else {
166→    console.warn("  ⚠️  skills/ (not found — no skills will be installed)");
167→  }
168→
169→  const hooksDir = join(OUTPUT_DIR, "hooks");
170→  if (existsSync(hooksDir)) {
171→    console.log("  ✅ hooks/");
172→  } else {
173→    console.log("  ℹ️  hooks/ (not included)");
174→  }
175→
176→  if (existsSync(join(OUTPUT_DIR, "README.md"))) {
177→    console.log("  ✅ README.md");
178→  } else {
179→    console.warn("  ⚠️  README.md (recommended for marketplace listing)");
180→  }
181→
182→  console.log("");
183→  if (errors > 0) {
184→    console.error(`❌ Validation failed with ${errors} error(s).`);
185→    process.exit(1);
186→  }
187→
188→  console.log("✅ Marketplace package is valid!");
189→  console.log(`\nPackage location: ${OUTPUT_DIR}`);
190→  console.log("\nNext steps:");
191→  console.log(`  1. Review the package: ls -la ${OUTPUT_DIR}`);
192→  console.log("  2. Submit via: https://clau.de/plugin-directory-submission");
193→  console.log(
194→    "  3. Reference: https://github.com/anthropics/claude-plugins-official",
195→  );
196→}
